callout-dogs-ear.general:
body.callout-dogs-ear .markdown-rendered .callout:after {
content: "";
position: absolute;
top: auto;
right: 0;
bottom: 0;
width: var(--callout-dogs-ear-size);
height: var(--callout-dogs-ear-size);
background: linear-gradient(to bottom right, rgba(200, 200, 200, 0.3) 50%, var(--background-primary) 50%);
-webkit-backdrop-filter: blur(2.5px);
backdrop-filter: blur(2.5px);
transition: width 0.2s, height 0.2s;
box-shadow: -1px 2px 3px 2px rgba(0, 0, 0, 0.2);
}

body.callout-dogs-ear .markdown-rendered .callout:hover:after {
width: 0;
height: 0;
}

embed-alt.general:
body.embed-alt .markdown-rendered .media-embed:after {
content: attr(alt);
font-family: var(--font-text);
font-size: 0.8em;
font-weight: 100;
color: var(--text-muted);
display: block;
width: 100%;
margin-top: 0.5em;
}

body.embed-alt-right .markdown-rendered .media-embed:after {
text-align: end;
}

body.embed-alt-left .markdown-rendered .media-embed:after {
text-align: start;
}

body.embed-alt-middle .markdown-rendered .media-embed:after {
text-align: center;
}

full-width-table.general:
body.full-width-table .markdown-rendered div:has(> table) {
width: 100%;
}

body.full-width-table .markdown-rendered div:has(> table) > table {
width: 100%;
}

top-bottom-table-border.general:
body.top-bottom-table-border .markdown-rendered div:has(> table) table {
border-top: 2px solid var(--text-normal);
border-bottom: 1px solid var(--text-normal);
}

center-table-header.general:
body.center-table-header .markdown-rendered div:has(> table) table th {
text-align: center;
}

tag-fill.general:
