toggle-style-default.general:
body.toggle-style-default .checkbox-container, body.toggle-style-default .checkbox-container.mod-small {
border: 1px solid var(--text-muted);
overflow-x: hidden;
border-radius: 1em;
transition: all 0.2s;
box-shadow: none;
width: 2.5em;
height: 1.4em;
padding-right: 0;
}

body.toggle-style-default .checkbox-container:focus-within, body.toggle-style-default .checkbox-container.mod-small:focus-within {
outline: none;
}

body.toggle-style-default .checkbox-container:hover, body.toggle-style-default .checkbox-container.mod-small:hover {
box-shadow: inset 2px 2px 5px 4px var(--switch-inset-shadow-color);
}

body.toggle-style-default .checkbox-container:after, body.toggle-style-default .checkbox-container.mod-small:after {
margin-top: 0;
transform: translateX(-1em);
width: 100%;
height: 100%;
transition: all 0.3s;
}

body.toggle-style-default .checkbox-container:active:after, body.toggle-style-default .checkbox-container.mod-small:active:after {
transform: translateX(-0.7em);
}

body.toggle-style-default .checkbox-container.is-enabled, body.toggle-style-default .checkbox-container.mod-small.is-enabled {
border: 1px solid var(--color-accent);
}

body.toggle-style-default .checkbox-container.is-enabled:hover, body.toggle-style-default .checkbox-container.mod-small.is-enabled:hover {
background-color: var(--color-accent);
}

body.toggle-style-default .checkbox-container.is-enabled:hover:after, body.toggle-style-default .checkbox-container.mod-small.is-enabled:hover:after {
box-shadow: -2px -2px 3px 2px var(--switch-inset-shadow-color);
}

body.toggle-style-default .checkbox-container.is-enabled:after, body.toggle-style-default .checkbox-container.mod-small.is-enabled:after {
transform: translateX(1em);
}

fade-out-inactive-lines.general:
.cm-embed-block) {
transition: var(--focus-transition-duration);
opacity: var(--inactive-opacity);
}

.cm-embed-block):hover {
opacity: var(--inactive-hover-opacity);
}

zen-mode.general:
body.zen-mode .status-bar {
transition: opacity 0.2s;
opacity: 0.1;
}

body.zen-mode .status-bar:hover {
opacity: 1;
}

body.zen-mode .side-dock-ribbon.is-collapsed {
border-right: none;
transition: opacity 0.3s;
opacity: 0;
}

body.zen-mode .side-dock-ribbon.is-collapsed:hover {
opacity: 1;
}

glassmorphism-command-palette.general:
body.glassmorphism-command-palette .prompt, body.glassmorphism-command-palette .graph-controls:not(.is-close), body.glassmorphism-command-palette .menu {
background-color: var(--background-color-glass) !important;
-webkit-backdrop-filter: blur(20px);
backdrop-filter: blur(20px);
}
